import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { AuthService } from '../../../../core/services/auth.service';

@Component({
  selector: 'app-forgot-password',
  templateUrl: './forgot-password.component.html',
  styleUrls: ['./forgot-password.component.scss'],
})
export class ForgotPasswordComponent {
  form: FormGroup;
  loading = false;
  success = '';
  error   = '';

  constructor(private fb: FormBuilder, private auth: AuthService) {
    this.form = this.fb.group({ email: ['', [Validators.required, Validators.email]] });
  }

  submit(): void {
    if (this.form.invalid) return;
    this.loading = true;
    this.auth.recuperarSenha(this.form.value.email).subscribe({
      next:  (r) => { this.success = r.message; this.loading = false; },
      error: (e) => { this.error = e.error?.message ?? 'Erro.'; this.loading = false; },
    });
  }
}
<div class="auth-page">
  <div class="auth-card">
    <div class="auth-logo">🔑</div>
    <h1 class="auth-title">Recuperar Senha</h1>
    <p class="auth-subtitle">Insira o seu email para receber o link de recuperação</p>

    <app-alert [message]="success" type="success" (dismiss)="success=''"></app-alert>
    <app-alert [message]="error"   type="error"   (dismiss)="error=''"></app-alert>

    <form [formGroup]="form" (ngSubmit)="submit()" novalidate>
      <div class="field">
        <label>{{ 'auth.email' | translate }}</label>
        <input
          type="email"
          formControlName="email"
          autocomplete="email"
          placeholder="email@exemplo.com"
        />
        <span class="field-error" *ngIf="form.get('email')?.touched && form.get('email')?.invalid">
          Email inválido
        </span>
      </div>

      <button
        type="submit"
        class="btn btn-primary btn-full"
        [disabled]="loading || form.invalid"
      >
        <app-loading-spinner [loading]="loading" [inline]="true"></app-loading-spinner>
        <span *ngIf="!loading">Enviar Link de Recuperação</span>
      </button>
    </form>

    <p class="auth-switch">
      <a routerLink="/auth/login">← Voltar ao login</a>
    </p>
  </div>
</div>
